import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // Defensive parser for holdings
  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("Corrupted holdings data:", e);
      return [];
    }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this strategy from the vault?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("WIPE_FAILED: DB_LOCK_ERROR");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_SYNTHESIS_FAILED");
    }
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={20} color="var(--accent-primary)" /> STRATEGY_VAULT
        </h2>
        <span style={nodeCount}>{history.length} NODES_STORED</span>
      </div>

      {history.length === 0 ? (
        <div style={emptyStyle}>
          No records found. Initialize a new strategy to populate the vault.
        </div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={10} /> {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={10} /> RISK_SCORE: {item.risk_score}
                  </span>
                </div>
                <h4 style={titleStyle}>{item.goal}</h4>

                <div style={tickerRow}>
                  {safeParseHoldings(item.holdings).map((t, i) => (
                    <span key={i} style={tickerTag}>
                      {t}
                    </span>
                  ))}
                </div>
              </div>

              <div style={actionRow}>
                <button
                  onClick={() => setSelectedItem(item)}
                  style={iconBtn}
                  title="View Rationale"
                >
                  <Eye size={18} />
                </button>
                <button
                  onClick={() => handleDownload(item)}
                  style={iconBtn}
                  title="Download PDF"
                >
                  <Download size={18} />
                </button>
                <button
                  onClick={() => handleDelete(item.id)}
                  style={deleteBtn}
                  title="Delete Record"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── STRATEGY PREVIEW MODAL ── */}
      {selectedItem && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3 style={{ margin: 0, fontSize: '0.95rem', fontWeight: 600 }}>
                STRATEGY PREVIEW // ID_{selectedItem.id}
              </h3>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}>
                <X size={20} />
              </button>
            </div>

            <div style={modalBody}>
              <div style={sectionBlock}>
                <div style={sectionTitle}>SUMMARY</div>
                <div style={descriptionText}>
                  {selectedItem.summary || 'No summary available.'}
                </div>
              </div>

              <div style={sectionBlock}>
                <div style={sectionTitle}>AGENTIC RATIONALE</div>
                <div style={descriptionText}>
                  {selectedItem.rationale || 'No detailed rationale provided.'}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ── Styles ── */
const containerStyle = {
  padding: '2rem 1.5rem',
  maxWidth: '1000px',
  margin: '0 auto',
  minHeight: '80vh',
};

const headerRow = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '2rem',
  borderBottom: '1px solid var(--surface-border)',
  paddingBottom: '1rem',
};

const headerStyle = {
  color: 'var(--text-primary)',
  display: 'flex',
  alignItems: 'center',
  gap: '12px',
  fontSize: '1.2rem',
  letterSpacing: '0.1em',
  margin: 0,
};

const nodeCount = {
  fontSize: '0.6rem',
  color: 'var(--text-muted)',
  fontFamily: 'monospace',
};

const listStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: '1.2rem',
};

const cardStyle = {
  display: 'flex',
  padding: '1.5rem',
  background: 'var(--surface-glass)',
  border: '1px solid var(--surface-border)',
  borderRadius: '16px',
  gap: '1.5rem',
  position: 'relative',
};

const tagRow = {
  display: 'flex',
  gap: '1rem',
  marginBottom: '0.75rem',
};

const dateTag = {
  fontSize: '0.6rem',
  color: 'var(--text-muted)',
  display: 'flex',
  alignItems: 'center',
  gap: '4px',
};

const riskTag = {
  fontSize: '0.6rem',
  color: 'var(--accent-primary)',
  fontWeight: 800,
  display: 'flex',
  alignItems: 'center',
  gap: '4px',
};

const titleStyle = {
  margin: '0 0 1rem',
  color: 'var(--text-primary)',
  fontSize: '1.05rem',
  fontWeight: 700,
  lineHeight: 1.4,
};

const tickerRow = {
  display: 'flex',
  flexWrap: 'wrap',
  gap: '6px',
};

const tickerTag = {
  fontSize: '0.65rem',
  padding: '3px 8px',
  background: 'rgba(16,185,129,0.1)',
  border: '1px solid var(--accent-primary)',
  borderRadius: '4px',
  color: 'var(--accent-primary)',
  fontFamily: 'monospace',
  fontWeight: 700,
};

const actionRow = {
  display: 'flex',
  flexDirection: 'column',
  gap: '0.8rem',
  borderLeft: '1px solid var(--surface-border)',
  paddingLeft: '1.5rem',
  justifyContent: 'center',
};

const iconBtn = {
  background: 'none',
  border: 'none',
  color: 'var(--text-secondary)',
  cursor: 'pointer',
  padding: '4px',
  transition: 'color 0.2s',
};

const deleteBtn = { ...iconBtn, color: '#ef4444' };

const centerStyle = {
  height: '60vh',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--accent-primary)',
  fontFamily: 'monospace',
  letterSpacing: '0.3em',
};

const emptyStyle = {
